```class Solution {
public:
    int maxFreq(string s, int maxLetters, int minSize, int maxSize) {
        unordered_map<string, int> freq;
        for (int i = 0; i <= s.size() - maxSize; i++) {
            string substr = s.substr(i, maxSize);
            if (substr.size() >= minSize) {
                unordered_set<char> uniqueChars(substr.begin(), substr.end());
                if (uniqueChars.size() <= maxLetters) {
                    freq[substr]++;
                }
            }
        }
        return *max_element(freq.begin(), freq.end(), [](const pair<string, int>& a, const pair<string, int>& b) {
            return a.second < b.second;
        })->second;
    }
};```
